Object.assign = null
import Starling from '../../src/index'
import { EN_TXT_CDN_ios, EN_TXT_CDN_frontend, EN_TXT_CDN_frontend_zh } from '../data/remote-demo-en'
import StarlingWeb from '../request'
async function waitInSec(timeInSec = 1) {
  await new Promise(resolve => {
    setTimeout(resolve, 1000 * timeInSec)
  })
}

const request = jest.fn()
const memoryStore = {
  _data: {},
  get(key) {
    return this._data[key]
  },
  set(key, value) {
    this._data[key] = value
  },
  del(key) {
    delete this._data[key]
  },
  clear() {
    this._data = {}
  }
} // 实现get/set方法的内存存储对象

const optionsCdn = {
  apiKey: 'de2eef103c0d11e99e27758535c50ad2',
  locale: 'en',
  namespace: 'frontend',
  zoneHost: '',
  timeout: 5000,
  cdn: 'https://lf3-cdn-tos.draftstatic.com/obj/ies.fe.starling/',
  tracker: () => {},
  request: request,
  store: memoryStore
}

class TestPlugin {
  type = 'afterLoad'
  constructor() {}

  async process(textMap, clientOps) {
    return {
      ...textMap,
      testplugin: 'test'
    }
  }
}

describe('集成测试-Starling Client Core CDN 测试', () => {
  test('load-成功-lazyUpdate:true-返回最新版本的本地缓存(保持原逻辑)', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '2', Lang: 'en', Data: EN_TXT_CDN_ios, Updated: true }
      }
    })
    const starling1 = new Starling(optionsCdn)
    // when
    await starling1.load()
    starling1.setConfig({ lazyUpdate: true })
    await starling1.load()
    const texts = await starling1.waitForRefresh()
    // then
    expect(texts).toEqual(EN_TXT_CDN_ios)
  })

  test('load - 成功 - 返回初始化参数中期待的语种', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'zh', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '2', Lang: 'en', Data: EN_TXT_CDN_ios, Updated: true }
      }
    })
    const starling1 = new Starling({ ...optionsCdn })
    await starling1.load()
    const texts = await starling1.load()

    const URL_LOAD_TEXT = `${optionsCdn.cdn}/${optionsCdn.apiKey}/normal/${optionsCdn.namespace}/${optionsCdn.locale}.json`
    expect(request).lastCalledWith(URL_LOAD_TEXT, { timeout: 5000 })
    expect(texts).toEqual(EN_TXT_CDN_ios)
  })
  test('load - 成功 - lazyUpdate多空间时本地缓存缺少一个load返回全部最新', async () => {
    request
      .mockImplementationOnce(() =>
        Promise.resolve({
          data: {
            status: 200,
            message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
          }
        })
      )
      .mockImplementationOnce(() =>
        Promise.resolve({
          data: {
            status: 200,
            message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_ios, Updated: true }
          }
        })
      )

    const starling = new Starling({
      ...optionsCdn,
      namespace: ['test1', 'test2'],
      lazyUpdate: true
    })
    // when
    const texts = await starling.load()
    // then 全部获取最新的文案
    expect(texts).toEqual({
      ...EN_TXT_CDN_frontend,
      ...EN_TXT_CDN_ios
    })
  })
  test('load - 失败 - 请求异常', async () => {
    // given
    request.mockRejectedValue('error')
    const starling = new Starling(optionsCdn)
    starling.load(
      () => {},
      e => {
        expect(e.code).toEqual(101)
      }
    )
  })

  test('load - 成功 - version: { test: 0.0.1} 传入版本也是通过cdn获取文案', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    const starling = new Starling({ ...optionsCdn, version: { test: '0.0.1' } })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT_CDN_frontend)
  })

  test('load-成功-CDN 配置 - tracker - 抛出异常也不影响正常运转', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    const starling = new Starling({
      ...optionsCdn,
      tracker: () => {
        throw new Error('error')
      }
    })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT_CDN_frontend)
  })

  test('load - 成功 - CDN 配置 - plugin插件执行', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    const starling = new Starling({
      ...optionsCdn,
      plugins: [new TestPlugin()]
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual({ ...EN_TXT_CDN_frontend, testplugin: 'test' })
  })

  test('初始化 - 失败', async () => {
    expect(() => {
      Object.assign(null)
      new Starling(null)
    }).toThrow()
  })

  test('load - 成功 - CDN 配置', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
      }
    })
    const starling = new Starling({
      ...optionsCdn
    })

    const texts = await starling.load()

    expect(texts).toEqual(EN_TXT_CDN_frontend)
  })

  test('load - 成功 - CDN 配置 - 多空间拉取', async () => {
    request
      .mockImplementationOnce(() =>
        Promise.resolve({
          data: {
            status: 200,
            message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true }
          }
        })
      )
      .mockImplementationOnce(() =>
        Promise.resolve({
          data: {
            status: 200,
            message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_ios, Updated: true }
          }
        })
      )

    const starling = new Starling({
      ...optionsCdn,
      namespace: ['frontend', 'ios']
    })

    const texts = await starling.load()

    expect(texts).toEqual({
      ...EN_TXT_CDN_frontend,
      ...EN_TXT_CDN_ios
    })
  })

  test('load - 成功 - CDN 配置 - format: splitted', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: {
          Version: '1720082294362255000',
          Lang: 'en',
          Data: EN_TXT_CDN_frontend,
          Updated: true
        }
      }
    })
    const starling = new Starling({
      ...optionsCdn,
      namespace: ['frontend'],
      format: 'splitted'
    })
    // when
    const texts = await starling.load()
    // then
    expect(texts).toEqual({
      frontend: {
        texts: EN_TXT_CDN_frontend,
        version: '1720082294362255000',
        lang: 'en'
      }
    })
  })

  test('load - 成功 - CDN 配置 - 兜底语种 - 单个兜底zh', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      fallbackLang: ['zh'],
      request: StarlingWeb
    })

    const texts = await starling.load()

    expect(texts).toEqual(EN_TXT_CDN_frontend_zh)
  })

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - 优先获取zh', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      fallbackLang: ['jb', 'zh', 'en'],
      request: StarlingWeb
    })

    const texts = await starling.load()

    expect(texts).toEqual(EN_TXT_CDN_frontend_zh)
  })

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - (只有zh有数据)', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      namespace: ['frontend'],
      fallbackLang: ['jb', 'ff', 'zh', 'zz'],
      request: StarlingWeb
    })

    const texts = await starling.load()

    expect(texts).toEqual(EN_TXT_CDN_frontend_zh)
  })

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - 全部失败，则空返回', async () => {
    // 返回空对象是因为于之前逻辑保持一致
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      fallbackLang: ['jb', 'ff', 'aa', 'abcd', 'zz'],
      request: StarlingWeb
    })

    const texts = await starling.load().catch(e => {})

    expect(texts).toEqual({})
  })
})
